"""Host-owned LocalAgentStore handlers for the Python SDK.

The Node bridge can delegate the *entire* local agent store (agents, runs,
run events, and checkpoint blobs) to the Python host process. This mirrors the
TypeScript SDK, where a caller passes a custom ``LocalAgentStore`` object. In
Python the store cannot cross the bridge as an object, so each substore
operation is forwarded over a loopback ``CallStore`` RPC and dispatched to the
handler defined here.

Wire shapes mirror ``@cursor/sdk``'s ``LocalAgentStore`` substore interfaces.
All keys are camelCase (the proto/JSON convention). Checkpoint blob bytes are
base64-encoded strings on the wire.

Implement ``LocalAgentStoreHandler`` (the substore protocols below) to own
where agent metadata, runs, run events, and checkpoint blobs are stored. The
test suite ships a complete in-memory implementation
(``tests/in_memory_local_store.py``) that doubles as a worked example, and
``tests/test_store_conformance.py`` pins the exact wire shape of every
operation.
"""

from __future__ import annotations

from collections.abc import Mapping
from typing import Any, Awaitable, Protocol, TypeVar, Union

_T = TypeVar("_T")
# A substore method may be sync or, when driven by an ``AsyncClient``, async.
MaybeAwaitable = Union[_T, Awaitable[_T]]


class StoreAgentsHandler(Protocol):
    """Agent rows. Mirrors ``LocalAgentStore.agents``."""

    def get(
        self, payload: Mapping[str, Any]
    ) -> MaybeAwaitable[dict[str, Any] | None]: ...
    def create(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def update(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def delete(self, payload: Mapping[str, Any]) -> MaybeAwaitable[None]: ...
    def list(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...


class StoreRunsHandler(Protocol):
    """Run rows. Mirrors ``LocalAgentStore.runs``."""

    def get(
        self, payload: Mapping[str, Any]
    ) -> MaybeAwaitable[dict[str, Any] | None]: ...
    def create(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def update(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def delete(self, payload: Mapping[str, Any]) -> MaybeAwaitable[None]: ...
    def list(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...


class StoreRunEventsHandler(Protocol):
    """Append-only run event log. Mirrors ``LocalAgentStore.runEvents``."""

    def append(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def list(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def delete(self, payload: Mapping[str, Any]) -> MaybeAwaitable[None]: ...


class StoreCheckpointsHandler(Protocol):
    """Content-addressed checkpoint blobs. Mirrors ``LocalAgentStore.checkpoints``.

    ``data`` is a base64-encoded string on the wire. ``get`` returns
    ``{"found": bool, "data"?: base64}``; ``list`` returns
    ``{"items": [blobId...], "nextCursor"?: str}``.
    """

    def get(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...
    def create(self, payload: Mapping[str, Any]) -> MaybeAwaitable[None]: ...
    def update(self, payload: Mapping[str, Any]) -> MaybeAwaitable[None]: ...
    def delete(self, payload: Mapping[str, Any]) -> MaybeAwaitable[None]: ...
    def list(self, payload: Mapping[str, Any]) -> MaybeAwaitable[dict[str, Any]]: ...


class LocalAgentStoreHandler(Protocol):
    """Fully host-owned local agent store.

    Provide one of these to ``Client.launch_bridge(..., store_handler=...)``
    (or ``Bridge.launch``) together with a ``local.store`` of type ``"custom"``
    to own where agent metadata, runs, run events, and checkpoint blobs live.

    Substore methods may be sync, or ``async`` when the store is driven by an
    ``AsyncClient`` / ``AsyncBridge`` (coroutines run on that client's event
    loop). Async methods with a sync ``Client`` raise at callback time.
    """

    @property
    def agents(self) -> StoreAgentsHandler: ...
    @property
    def runs(self) -> StoreRunsHandler: ...
    @property
    def run_events(self) -> StoreRunEventsHandler: ...
    @property
    def checkpoints(self) -> StoreCheckpointsHandler: ...


def is_local_agent_store_handler(handler: object) -> bool:
    """True when ``handler`` looks like a full ``LocalAgentStoreHandler``."""
    return all(
        hasattr(handler, attr)
        for attr in ("agents", "runs", "run_events", "checkpoints")
    )


def dispatch_store_op(
    handler: LocalAgentStoreHandler,
    substore: str,
    method: str,
    payload: Mapping[str, Any],
) -> Any:
    """Route a generic ``CallStore`` operation to ``handler``'s substore."""
    substores = {
        "agents": handler.agents,
        "runs": handler.runs,
        "runEvents": handler.run_events,
        "checkpoints": handler.checkpoints,
    }
    target = substores.get(substore)
    if target is None:
        raise ValueError(f"Unknown store substore: {substore}")
    operation = getattr(target, method, None)
    if operation is None or not callable(operation):
        raise ValueError(f"Unknown {substore} operation: {method}")
    return operation(payload)
